/**
 * hwpx 원본 템플릿 (base64 인코딩)
 * consent-hwpx 스킬의 assets/originals 에서 추출
 */

const domesticnosignup = "";

const domesticwithsignup = "";

const foreignnosignup = "";

export const TEMPLATES = {
  "domestic_no_signup.hwpx": domesticnosignup,
  "domestic_with_signup.hwpx": domesticwithsignup,
  "foreign_no_signup.hwpx": foreignnosignup,
};

/**
 * base64 문자열을 ArrayBuffer로 변환
 */
export function decodeTemplate(b64str) {
  const binary = atob(b64str);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

/**
 * 모든 템플릿을 ArrayBuffer로 변환하여 반환
 */
export function getTemplateBuffers() {
  const buffers = {};
  for (const [name, b64] of Object.entries(TEMPLATES)) {
    buffers[name] = decodeTemplate(b64);
  }
  return buffers;
}
